//! Rust-side tests for the NAPI inference kernels.
//!
//! These tests bypass the NAPI `Buffer` wrappers and call `*_impl` free
//! functions directly; the `#[napi]` boundary is a thin casting layer.

use super::{
    forward_ffn_column_tp_impl, forward_median_shift_attention_impl,
    forward_multihead_attention_impl,
};

fn deterministic_vec(n: usize, seed: u32) -> Vec<f32> {
    // Simple xorshift32 -> [-1, 1]; enough entropy to avoid degenerate softmax.
    let mut s = seed.wrapping_mul(2654435761).max(1);
    (0..n)
        .map(|_| {
            s ^= s << 13;
            s ^= s >> 17;
            s ^= s << 5;
            // map to [-1, 1]
            ((s as i32) as f32) / (i32::MAX as f32)
        })
        .collect()
}

// ---------------------------------------------------------------------------
// Median-shift attention
// ---------------------------------------------------------------------------

#[test]
fn median_shift_mass_conservation() {
    // Z_full should equal Z_kept + Z_dropped (mass conservation lemma). Here
    // we verify the aggregate telemetry is internally consistent.
    let seq_len = 32;
    let head_dim = 16;
    let num_heads = 4;
    let num_kv_heads = 2;
    let scale = 1.0 / (head_dim as f32).sqrt();

    let q = deterministic_vec(num_heads * head_dim, 1);
    let k = deterministic_vec(num_kv_heads * seq_len * head_dim, 2);
    let v = deterministic_vec(num_kv_heads * seq_len * head_dim, 3);
    let mut out = vec![0.0f32; num_heads * head_dim];

    // Ceiling = 1.0 forces zero fallbacks so every head exercises the kept path.
    let tel = forward_median_shift_attention_impl(
        &q,
        &k,
        &v,
        &mut out,
        seq_len,
        head_dim,
        num_heads,
        num_kv_heads,
        scale,
        1.0,
    )
    .expect("median-shift kernel should succeed");

    // Telemetry sanity.
    assert_eq!(tel.seq_len, (num_heads * seq_len) as u32);
    assert_eq!(
        tel.kept_count + tel.dropped_count,
        (num_heads * seq_len) as u32
    );
    assert_eq!(tel.fallback_head_count, 0, "no head should fall back");
    assert!(!tel.fell_back_to_full_softmax);

    // Output must be finite.
    for &v in &out {
        assert!(v.is_finite(), "output must be finite, got {}", v);
    }

    // z_full > 0 and z_full > z_dropped (we kept at least one position per head).
    assert!(tel.z_full > 0.0);
    assert!(tel.z_full > tel.z_dropped);
    // dropped_mass_fraction must be in [0, 1].
    assert!(tel.dropped_mass_fraction >= 0.0);
    assert!(tel.dropped_mass_fraction <= 1.0);
}

#[test]
fn median_shift_ceiling_triggers_fallback() {
    // With a tiny ceiling (0.0), every head with any dropped mass must fall
    // back to full softmax.
    let seq_len = 16;
    let head_dim = 8;
    let num_heads = 2;
    let num_kv_heads = 1;
    let scale = 1.0 / (head_dim as f32).sqrt();

    let q = deterministic_vec(num_heads * head_dim, 10);
    let k = deterministic_vec(num_kv_heads * seq_len * head_dim, 20);
    let v = deterministic_vec(num_kv_heads * seq_len * head_dim, 30);
    let mut out = vec![0.0f32; num_heads * head_dim];

    let tel = forward_median_shift_attention_impl(
        &q,
        &k,
        &v,
        &mut out,
        seq_len,
        head_dim,
        num_heads,
        num_kv_heads,
        scale,
        0.0,
    )
    .unwrap();

    assert!(tel.fell_back_to_full_softmax);
    assert!(tel.fallback_head_count >= 1);
}

#[test]
fn median_shift_matches_full_softmax_when_disabled() {
    // With ceiling=0.0 and entirely above-median scores... actually, easier: a
    // disabled cut should match full multi-head attention to ~eps. We simulate
    // disabling by setting a very small ceiling so every head falls back.
    let seq_len = 24;
    let head_dim = 12;
    let num_heads = 3;
    let num_kv_heads = 3;
    let scale = 1.0 / (head_dim as f32).sqrt();

    let q = deterministic_vec(num_heads * head_dim, 100);
    let k = deterministic_vec(num_kv_heads * seq_len * head_dim, 200);
    let v = deterministic_vec(num_kv_heads * seq_len * head_dim, 300);

    let mut out_median = vec![0.0f32; num_heads * head_dim];
    forward_median_shift_attention_impl(
        &q,
        &k,
        &v,
        &mut out_median,
        seq_len,
        head_dim,
        num_heads,
        num_kv_heads,
        scale,
        0.0, // force fallback on any drop
    )
    .unwrap();

    let mut out_full = vec![0.0f32; num_heads * head_dim];
    forward_multihead_attention_impl(
        &q,
        &k,
        &v,
        &mut out_full,
        seq_len,
        head_dim,
        num_heads,
        num_kv_heads,
        scale,
    )
    .unwrap();

    // Fallback path should be bit-identical to the dense reference up to
    // summation order. Use a loose epsilon.
    for (a, b) in out_median.iter().zip(out_full.iter()) {
        assert!(
            (a - b).abs() < 1e-4,
            "fallback mismatch: median={} full={}",
            a,
            b
        );
    }
}

// ---------------------------------------------------------------------------
// Column-parallel SwiGLU FFN
// ---------------------------------------------------------------------------

fn ffn_monolithic(
    x: &[f32],
    w_up: &[f32],
    w_gate: &[f32],
    w_down: &[f32],
    seq_len: usize,
    hidden: usize,
    inter: usize,
) -> Vec<f32> {
    // Baseline, no sharding, same math. Serves as the oracle.
    let mut out = vec![0.0f32; seq_len * hidden];
    let mut up = vec![0.0f32; seq_len * inter];
    let mut gate = vec![0.0f32; seq_len * inter];
    for s in 0..seq_len {
        for c in 0..inter {
            let mut u = 0.0f32;
            let mut g = 0.0f32;
            for h in 0..hidden {
                let xv = x[s * hidden + h];
                u += xv * w_up[h * inter + c];
                g += xv * w_gate[h * inter + c];
            }
            up[s * inter + c] = u;
            gate[s * inter + c] = g;
        }
    }
    let mut act = vec![0.0f32; seq_len * inter];
    for i in 0..act.len() {
        let g = gate[i];
        let sig = 1.0f32 / (1.0 + (-g).exp());
        act[i] = g * sig * up[i];
    }
    for s in 0..seq_len {
        for h_out in 0..hidden {
            let mut acc = 0.0f32;
            for c in 0..inter {
                acc += act[s * inter + c] * w_down[c * hidden + h_out];
            }
            out[s * hidden + h_out] = acc;
        }
    }
    out
}

#[test]
fn ffn_tp_matches_monolithic_single_shard() {
    let seq_len = 4;
    let hidden = 8;
    let inter = 16;

    let x = deterministic_vec(seq_len * hidden, 7);
    let w_up = deterministic_vec(hidden * inter, 11);
    let w_gate = deterministic_vec(hidden * inter, 13);
    let w_down = deterministic_vec(inter * hidden, 17);

    let baseline = ffn_monolithic(&x, &w_up, &w_gate, &w_down, seq_len, hidden, inter);

    let mut out = vec![0.0f32; seq_len * hidden];
    forward_ffn_column_tp_impl(
        &x, &w_up, &w_gate, &w_down, &mut out, seq_len, hidden, inter, 1,
    )
    .unwrap();

    for (a, b) in out.iter().zip(baseline.iter()) {
        assert!(
            (a - b).abs() < 1e-5,
            "single-shard mismatch: {} vs {}",
            a,
            b
        );
    }
}

#[test]
fn ffn_tp_matches_monolithic_multi_shard() {
    let seq_len = 3;
    let hidden = 8;
    let inter = 32;
    let shards = 8;

    let x = deterministic_vec(seq_len * hidden, 21);
    let w_up = deterministic_vec(hidden * inter, 22);
    let w_gate = deterministic_vec(hidden * inter, 23);
    let w_down = deterministic_vec(inter * hidden, 24);

    let baseline = ffn_monolithic(&x, &w_up, &w_gate, &w_down, seq_len, hidden, inter);

    let mut out = vec![0.0f32; seq_len * hidden];
    forward_ffn_column_tp_impl(
        &x, &w_up, &w_gate, &w_down, &mut out, seq_len, hidden, inter, shards,
    )
    .unwrap();

    // Sharded summation order differs; allow 1e-5 epsilon per the brief.
    for (a, b) in out.iter().zip(baseline.iter()) {
        assert!(
            (a - b).abs() < 1e-5,
            "multi-shard mismatch: sharded={} mono={}",
            a,
            b
        );
    }
}

#[test]
fn ffn_tp_rejects_non_divisible_shards() {
    let seq_len = 2;
    let hidden = 4;
    let inter = 5; // not divisible by 2
    let x = vec![0.0f32; seq_len * hidden];
    let w_up = vec![0.0f32; hidden * inter];
    let w_gate = vec![0.0f32; hidden * inter];
    let w_down = vec![0.0f32; inter * hidden];
    let mut out = vec![0.0f32; seq_len * hidden];
    let err = forward_ffn_column_tp_impl(
        &x, &w_up, &w_gate, &w_down, &mut out, seq_len, hidden, inter, 2,
    )
    .expect_err("must reject non-divisible shard count");
    assert!(err.contains("divisible"));
}
